('14cfd9c4-32f6-4f3c-8770-b617a94b0af6', 'c90df0ac-3ec9-4c05-b165-8166320a0e35', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'campo_atualizado', 'editou: Status', NULL, NULL, NULL, '2026-02-03T19:30:30.833Z', NULL, NULL, NULL, NULL, NULL, false),
('0edd30f3-491d-44e9-8d70-b498ffb6db8b', '00d2f3a5-08e1-4624-bc35-5d85ed81f1c5', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Discussão do Edital CISMISEL (Sete Lagoas, MG) Luana Barros - Gestão Serviço Saúde apresentou o primeiro pregão, que é do SISMEL em Sete Lagoas, Minas Gerais, e inclui consultas em diversas especialidades e exames, como ultrassonografi as ginecológicas (00:03:14). O edital apresenta quatro lotes de consultas, incluindo neuropediatria, cardiologia (que exige residência médica ou título de especialista), e ortopedia, e um lote de exames de ultrassom (00:03:45). Joao Henrique Cunha Villela perguntou sobre a periodicidade das 80 consultas mensais (se precisava ser semanal), pois essa informação é crucial para a viabilidade do deslocamento dos prestadores (00:04:48).
● Decisão sobre a Deliberação do Edital SISMEL Joao Henrique Cunha Villela indicou que só deliberaria sobre o edital de SISMEL após ter a resposta sobre se o edital exige uma periodicidade semanal para o cumprimento das consultas (00:04:48). O edital é para 12 de fevereiro, dando tempo hábil para fazer o questionamento até a próxima sexta-feira (00:05:35', NULL, NULL, NULL, '2026-02-03T19:34:01.228Z', NULL, NULL, NULL, NULL, NULL, false),
('b89f1cc7-c231-47af-9f84-7a9fcb62fbd8', '22dcb4a6-f7e7-4812-be00-053c229f4471', 'dfe5defb-39c7-457d-ad26-2e463d4cdb58', 'comentario', '@Sarah Salustiano é fundamental que a empresa avalie quais itens da licitação ela pretende concorrer e, com base nisso, apresente os atestados de capacidade técnica correspondentes, seja institucional, clínico, ou ambos, conforme a natureza dos serviços para os quais está se habilitando.', NULL, NULL, NULL, '2026-02-03T19:38:26.210Z', NULL, NULL, NULL, NULL, NULL, false),
('a763695a-3e19-4ad2-ad1e-e7deb462fbd7', '00d2f3a5-08e1-4624-bc35-5d85ed81f1c5', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'ESCLARECIMENTO REGISTRADO NO SITE', NULL, NULL, NULL, '2026-02-03T19:41:45.271Z', NULL, NULL, NULL, NULL, NULL, false),
