('a0a44002-b2b9-44dd-b3f7-4927ffcb9e72', '00d2f3a5-08e1-4624-bc35-5d85ed81f1c5', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Processo Sis Mizel de Sete Lagoas (Minas Gerais) Luana Barros - Gestão Serviço Saúde deu seguimento à discussão sobre o processo Sis Mizel de Sete Lagoas, confi rmando que as consultas poderiam ser realizadas mensalmente ( 00:22:22 ). Bianca Santos - Gestão Serviço Saúde complementou que a empresa já possuía um contrato de cardiologia (Cardio) e ortopedia (Orto) com o consórcio, embora este novo edital fosse para outras cidades do consórcio ( 00:23:07 ). As especialidades deste novo edital incluem Cardiologia (80 mensais a R$108), Ortopedia (100 mensais a R$85), Neuropediatria (130 mensais), e exames de USG ginecológicos (75 mensais, com equipamento já fornecido pelo consórcio) ( 00:24:01 ). O valor total do edital é sigiloso, mas a equipe concordou em seguir os valores mínimos da tabela interna para as consultas (R$99 para Cardio e R$79 para Orto), e R$59 para USG sem Doppler ( 00:26:03 ).', NULL, NULL, NULL, '2026-02-09T11:07:30.224Z', NULL, NULL, NULL, NULL, NULL, false),
('360868aa-33ac-404e-9182-621814242e46', '00d2f3a5-08e1-4624-bc35-5d85ed81f1c5', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', '@Emmily Cristini 
VALORES MINIMOS DELIBERADOS: (R$99 para Cardio  //  R$79 para Orto), e R$59 para USG sem Doppler', NULL, NULL, NULL, '2026-02-09T11:09:03.874Z', NULL, NULL, NULL, NULL, NULL, false),
('003213c7-9f57-4aca-9639-c6200b9c4049', '00d2f3a5-08e1-4624-bc35-5d85ed81f1c5', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'campo_atualizado', 'editou: Status', NULL, NULL, NULL, '2026-02-09T11:09:15.848Z', NULL, NULL, NULL, NULL, NULL, false),
