('7b05574a-cea3-43c5-aca6-6270c18c584b', 'f1620cf7-e851-452c-a281-5de6c0ff11da', 'dfe5defb-39c7-457d-ad26-2e463d4cdb58', 'comentario', 'Sim, para médico especialista, o responsável técnico deve ter diploma de médico especialista, CRM ativo e RQE ou certificado de pós-graduação com carga horária igual ou acima de 360 horas.', NULL, NULL, NULL, '2026-03-10T14:11:43.710Z', NULL, NULL, NULL, NULL, NULL, false),
