('6a1e123c-a7d2-4a11-b860-e3a99a96a03a', 'fd7c49a5-bbb8-4b9d-b667-ef6ced650cf9', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Licitação para Atendimento Virtual em Tubarão (CISA Murel): Luana Barros apresentou um processo de licitação do consórcio CISA Murel em Tubarão para a contratação de uma empresa para operar um pronto atendimento virtual. A empresa contratada deverá fornecer a plataforma, suporte técnico e médicos para especialidades como Clínico Geral, Médico de Família com RQE e Pediatra com RQE, todos trabalhando 24 horas por dia, 7 dias por semana (00:00:00). Foi discutida a qualificação técnica exigida, que inclui ter serviço prévio para uma população de 140.000 pessoas por um período de quatro meses, o que foi considerado um ponto crítico (00:06:14).', NULL, NULL, NULL, '2026-03-23T20:03:17.424Z', NULL, NULL, NULL, NULL, NULL, false),
('1304c5f1-f1d9-4bd2-bdd2-2c5a8b862178', '68fbc9fc-5d52-46fe-a437-33c4f67b16df', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', '02 profissionais 20h', NULL, NULL, NULL, '2026-03-24T11:03:05.880Z', NULL, NULL, NULL, NULL, NULL, false),
