('7add90d9-6d45-4908-950c-7cfc7183a73a', '817c8a97-f9e5-4cf3-b369-a504dbb9743c', '5842d696-5e72-4798-9e5a-eb5d8268998a', 'comentario', 'Licitação criada via n8n (Effect ID: 7407184)', NULL, NULL, NULL, '2026-03-19T20:04:58.211Z', NULL, NULL, NULL, NULL, NULL, false),
('d87ed571-2b01-4c70-a7d1-cbcace9ae964', 'c19895bd-576e-4e86-b53e-5703800fbbad', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Retorno sobre Impugnação em São Gonçalo (RJ): Foi apresentado o resultado da impugnação do processo em São Gonçalo (RJ), que misturava especialidades médicas e outros profissionais. A impugnação foi indeferida, pois o órgão argumentou que não fará alterações no edital (00:21:00). Maikon Madeira alertou para a complexidade e os riscos de participar de processos em São Gonçalo, na Baixada Fluminense (00:21:53).', NULL, NULL, NULL, '2026-03-20T10:22:34.952Z', NULL, NULL, NULL, NULL, NULL, false),
('a3a7f14e-40f6-408f-b404-6cb5d71b84e0', 'c19895bd-576e-4e86-b53e-5703800fbbad', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'campo_atualizado', 'editou: Status', NULL, NULL, NULL, '2026-03-20T10:23:07.928Z', NULL, NULL, NULL, NULL, NULL, false),
('9fb062f1-41f0-4e41-a4d5-038cf1825f6e', 'dc8b9de0-e3d5-4532-8378-cf8698a86617', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Lote de Clínico Geral em São Gabriel do Oeste (MS): O processo em São Gabriel do Oeste também inclui consulta médica ambulatorial com clínico geral, com 42 consultas previstas por mês e valor de R$91 por consulta (00:12:20). Luana Barros irá questionar a administração do edital se o número de 42 consultas por mês (cerca de um dia de atendimento) está correto, dado que o horário de atendimento possível é das 7h às 17h (00:18:21).', NULL, NULL, NULL, '2026-03-20T10:23:59.261Z', NULL, NULL, NULL, NULL, NULL, false),
('c0aa5842-8950-47ce-a8b2-a6710b61c8a1', 'dc8b9de0-e3d5-4532-8378-cf8698a86617', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'campo_atualizado', 'editou: Status, Etiquetas', NULL, NULL, NULL, '2026-03-20T10:28:30.578Z', NULL, NULL, NULL, NULL, NULL, false),
('888e2ca8-ec7c-4ef4-92ce-0f90eec13975', '6249ad8c-d316-4431-bbe5-7b4b153cccc3', 'dfe5defb-39c7-457d-ad26-2e463d4cdb58', 'comentario', 'Policlínica Municipal, PSFs e domicílios no Município de Pilões, PB.', NULL, NULL, NULL, '2026-03-20T11:53:27.711Z', NULL, NULL, NULL, NULL, NULL, false),
('9c9d9ee9-4735-4841-847a-7caa0c8b2fb0', '6249ad8c-d316-4431-bbe5-7b4b153cccc3', 'dfe5defb-39c7-457d-ad26-2e463d4cdb58', 'comentario', '12.4.5. Registros de Qualificações dos Especialistas (RQE) junto ao Conselho Regional de Medicina (CRM).', NULL, NULL, NULL, '2026-03-20T11:55:20.650Z', NULL, NULL, NULL, NULL, NULL, false),
('7660ba23-71df-47ed-baa0-0c764c09766b', 'dc8b9de0-e3d5-4532-8378-cf8698a86617', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Processo de Psiquiatria em São Gabriel do Oeste (MS): Foi introduzido o processo de São Gabriel do Oeste (MS), uma cidade de 29.000 habitantes, próxima a Campo Grande (00:11:32). O processo inclui consultas médicas em Psiquiatria (com RQE), com valor de R$278 por consulta, totalizando 116 consultas previstas por mês (00:12:20). A ideia é realizar quatro ambulatórios semanais com duração média de 30 minutos por paciente, funcionando das 7 às 17h, o que totalizaria cerca de 16 consultas em 8 horas (00:14:45) (00:16:09). O preço mínimo definido para a consulta de psiquiatria é R$269 (00:17:28)', NULL, NULL, NULL, '2026-03-20T10:29:15.310Z', NULL, NULL, NULL, NULL, NULL, false),
('a3159dbf-7444-4364-8cf9-20e13a8bc42a', 'b7b6609b-b700-4b28-8394-9e9f0a94b5fd', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Processo de CTI em Varginha (MG): O processo de Varginha, cidade com 136.000 habitantes, visa o atendimento em uma fundação hospitalar na área de CTI/UTI e é um lote único (00:08:37). Os itens incluem plantão de 12 horas para médico de CTI (R$177 por hora), médico diarista para CTI (R$10.110/mês, mínimo de 2 horas diárias), médico do CTI Anexo (R$10.110/mês), e coordenador de UTI (R$22.000/mês) (00:09:23). Foi ressaltado que os cargos de diarista e coordenador requerem RQE, e o valor total do processo é R$3.676.000 (00:10:00). A equipe expressou a necessidade de vencer essa licitação e ficou combinado que Maikon Madeira pesquisará os preços para discussão e deliberação na próxima reunião (00:10:45).', NULL, NULL, NULL, '2026-03-20T10:30:05.829Z', NULL, NULL, NULL, NULL, NULL, false)
ON CONFLICT (id) DO NOTHING;

INSERT INTO "licitacoes_atividades" ("id", "licitacao_id", "user_id", "tipo", "descricao", "campo_alterado", "valor_antigo", "valor_novo", "created_at", "resposta_esperada_ate", "responsavel_resposta_id", "setor_responsavel", "respondido_em", "respondido_por", "is_critico") VALUES
('35e81ce0-4847-4e95-ab6a-2882d28e10cc', '0c893418-ecb5-47b5-95fd-edaf1a61ceff', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Processos por Especialidade em Chuvisca (RS): Discutiu-se o processo na cidade de Chuvisca (RS), que fica a duas horas de Pelotas, onde há quatro lotes por especialidade e valor por hora, permitindo que a equipe escolha os itens que deseja concorrer (00:03:48). Um dos itens é para clínico geral em Unidade Básica de Saúde (UBS) 24 horas diárias, de segunda a domingo, com o valor máximo de R$154 e o valor mínimo definido em R$69,90 (00:06:02). Foi solicitado a Felipe Graeff que compartilhasse fotos da UBS para avaliação da situação local (00:06:41).
Lote de Ginecologia e Obstetrícia em Chuvisca (RS): O lote para Ginecologia e Obstetrícia em Chuvisca prevê uma carga horária de 8 horas diárias, de segunda a sexta-feira, com valor por hora de R$200. Considerando a especialidade, foi sugerido que o valor mínimo fosse estabelecido em R$197,90, pois não seria possível reduzir muito o preço (00:07:28).
Lotes de Pediatria e Psiquiatria em Chuvisca (RS): Os lotes de Pediatria e Psiquiatria em Chuvisca, ambos com 8 horas diárias para UBS e valor por hora de R$200, foram considerados inviáveis e a equipe decidiu sair desses itens (00:08:00). Assim, o foco em Chuvisca será nos itens de Clínico Geral e Ginecologia (00:08:37).', NULL, NULL, NULL, '2026-03-20T10:31:08.692Z', NULL, NULL, NULL, NULL, NULL, false),
('42f0830c-b69c-4382-abde-d971d4c73659', '0c893418-ecb5-47b5-95fd-edaf1a61ceff', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'campo_atualizado', 'editou: Status', NULL, NULL, NULL, '2026-03-20T10:31:19.357Z', NULL, NULL, NULL, NULL, NULL, false),
('866e6b88-a18c-4be6-bfb1-fb9dad79a5f5', 'f667070c-33ba-4380-a9b0-c0c0077e9587', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Processo de Clínico Geral em Sentinela do Sul (RS): Foi apresentado um processo na cidade de Sentinela do Sul (RS), que fica próximo a Pelotas, para plantão médico de clínico geral em dois lotes distintos (00:01:51). O primeiro lote cobre integralmente o atendimento de urgência e emergência, 24 horas por dia (incluindo fins de semana), com valor por hora de R$169, e o segundo lote, também para clínico geral, prevê 80 horas mensais para atendimento a pacientes crônicos, pequenos procedimentos cirúrgicos e regulação. O valor mínimo da hora foi estabelecido em R$111,90, após sugestão de Maikon Madeira para um preço mais competitivo no dia da licitação (00:02:55).', NULL, NULL, NULL, '2026-03-20T10:31:56.724Z', NULL, NULL, NULL, NULL, NULL, false),
('373eb6b9-bb55-4344-b7d9-7601edf74f70', 'f667070c-33ba-4380-a9b0-c0c0077e9587', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'campo_atualizado', 'editou: Objeto', NULL, NULL, NULL, '2026-03-20T10:33:40.940Z', NULL, NULL, NULL, NULL, NULL, false),
('d30a67e3-bf42-4301-85c5-3bd75bf364d3', '64303bdf-86e3-4144-b18f-05cbfd35f4a7', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Processo de Cardiologia em São Mateus (ES): O primeiro processo discutido é referente à especialidade de cardiologia para atendimento no hospital estadual Roberto Silvares, em São Mateus, Espírito Santo, uma cidade com 123.000 habitantes. O processo envolve oito profissionais, com um coordenador médico trabalhando por 12 horas e ganhando R$199 por hora, e sete outros cardiologistas para atendimento ambulatorial, pareceres e consultas de retorno, também com valor por hora de R$199 (00:00:00).', NULL, NULL, NULL, '2026-03-20T10:34:26.000Z', NULL, NULL, NULL, NULL, NULL, false),
('ae79c9da-347f-4b26-961c-a85bce47a5ab', 'f1e3fee2-7630-4160-8f6e-ce37293ea36b', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Retorno sobre Credenciamento em Juiz de Fora (MG): Houve um retorno sobre um credenciamento anterior em Juiz de Fora (MG) para ortopedia e cirurgias. O órgão licitante informou que não possui caixas de material cirúrgico, o que exige que a contratada forneça a equipe técnica, anestesista, instrumentais e equipamentos (00:18:59). A equipe considerou a condição complicada e decidiu descartar a participação nesse processo (00:19:54).', NULL, NULL, NULL, '2026-03-20T10:36:03.523Z', NULL, NULL, NULL, NULL, NULL, false),
