('13b7805c-b59d-40aa-b302-9b3f2c7a1b29', 'f1b14a71-cd09-4327-a0dc-afa1049148d7', 'dfe5defb-39c7-457d-ad26-2e463d4cdb58', 'campo_atualizado', 'editou: Responsável', NULL, NULL, NULL, '2026-03-31T10:42:34.780Z', NULL, NULL, NULL, NULL, NULL, false),
('ad840c65-39b3-41f3-a564-9ab19d56b2f8', '0559b57d-2db3-4e3d-b4f0-bfcc58a76a3b', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'comentario', 'Licitação para Serviços Médicos em Miraguaí, Rio Grande do Sul: A licitação para Miraguaí, uma cidade com 4.440 habitantes próxima a Chapecó, visa atender a uma Unidade Básica de Saúde (UBS) em lote único (00:21:59). O valor horário para dois clínicos gerais de 40 horas semanais é de R$ 147,98, e o valor sugerido para pagamento é R$ 90,90 por hora. Para o RT de 40 horas, com um valor horário de R$ 176,00, foi sugerido utilizar o mesmo valor de R$ 90,90, pois não é exigido RQE (00:22:51).', NULL, NULL, NULL, '2026-03-31T10:43:41.195Z', NULL, NULL, NULL, NULL, NULL, false),
('550c25d3-f95b-4877-80c9-80b1ef7951fe', '0559b57d-2db3-4e3d-b4f0-bfcc58a76a3b', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'campo_atualizado', 'editou: Status', NULL, NULL, NULL, '2026-03-31T10:43:59.185Z', NULL, NULL, NULL, NULL, NULL, false),
