('23030596-b143-41e5-980f-1043aac84a2c', '073bc9e7-9139-4ead-beea-a4d6bef450b0', '3adafddc-3d23-40c6-8ce0-5ddf0d3aef0b', 'status_alterado', 'Status alterado de "capitacao_de_credenciamento" para "edital_analise', 'status', 'capitacao_de_credenciamento', 'edital_analise', '2026-03-31T16:06:06.319Z', NULL, NULL, NULL, NULL, NULL, false),
